import { callMcpSkill } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  // Step 1: Sequential discovery — two broad searches on the same endpoint
  const search1 = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "search_markets",
    args: { query: "US boots on the ground Iran military invasion troops", limit: 20, status: "live" }
  });

  const search2 = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "search_markets",
    args: { query: "Iran war conflict strike attack allied forces ground", limit: 20, status: "live" }
  });

  // Deduplicate by conditionId
  const seen = new Set();
  const allCandidates = [];
  for (const r of [...(search1.results || []), ...(search2.results || [])]) {
    if (r.conditionId && !seen.has(r.conditionId)) {
      seen.add(r.conditionId);
      allCandidates.push(r);
    }
  }

  // Step 2: Semantic targeting — rank combined results against the core scenario
  const ranked = pickTopSemanticCandidates({
    target: "US or allied military boots on the ground in Iran — direct troop deployment, invasion, or sustained ground presence",
    candidates: allCandidates,
    requiredTerms: ["iran", "troop", "ground", "boots", "military", "invas", "forces", "war"],
    avoidTerms: ["sanctions", "nuclear", "deal", "diplomat", "negotiat", "embassy"],
    limit: 8
  });

  // Step 3: Sequential deep analysis on the semantic shortlist
  const analyses = [];
  for (const m of ranked) {
    const efficiency = await callMcpSkill({
      toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
      toolName: "check_market_efficiency",
      args: { conditionId: m.conditionId }
    });

    const rules = await callMcpSkill({
      toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
      toolName: "check_market_rules",
      args: { conditionId: m.conditionId }
    });

    analyses.push({
      title: m.title,
      url: m.url,
      status: m.status,
      endDate: m.endDate,
      liquidity: m.liquidity,
      volume: m.volume,
      conditionId: m.conditionId,
      efficiency: efficiency.marketEfficiency,
      trueProbabilities: efficiency.trueProbabilitiesPercent || efficiency.trueProbabilities,
      outcomes: efficiency.outcomes,
      rulesSummary: rules.rulesSummary,
      resolutionSource: rules.resolutionSource,
      riskFactors: rules.riskFactors,
      description: rules.description ? rules.description.slice(0, 300) : undefined
    });
  }

  // Step 4: Separate semantic search for correlated risk-off instruments (oil)
  const oilSearch = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "search_markets",
    args: { query: "oil price crude Brent WTI spike geopolitical risk", limit: 10, status: "live" }
  });

  const oilRanked = pickTopSemanticCandidates({
    target: "crude oil price spike from geopolitical risk — Brent or WTI reaching specific high price thresholds",
    candidates: oilSearch.results || [],
    requiredTerms: ["oil", "crude", "brent", "wti", "price"],
    avoidTerms: ["iran", "troop", "invas"],
    limit: 5
  });

  const oilMarkets = oilRanked.map(r => ({
    title: r.title,
    url: r.url,
    endDate: r.endDate,
    liquidity: r.liquidity,
    volume: r.volume
  }));

  return {
    query: "US/allied boots on the ground in Iran",
    totalCandidatesDiscovered: allCandidates.length,
    semanticShortlistSize: ranked.length,
    relevantMarketsAnalyzed: analyses.length,
    markets: analyses,
    correlatedRiskOffMarkets: oilMarkets,
    riskOffFramework: {
      summary: "Iran military escalation markets on Polymarket provide implied probabilities for direct troop deployment. These prices can be used as a real-time geopolitical risk gauge. For risk-off positioning, consider: (1) the spread between Iran troop markets and broader oil/sanctions markets as a hedge ratio, (2) resolution rule differences across markets—some require 'declared' invasions vs 'any' ground presence, (3) temporal clustering of resolution dates creates rolling risk windows rather than binary events.",
      keyConsiderations: [
        "Rule definition matters enormously—'boots on the ground' vs 'declared war' vs 'sustained military operation' are very different thresholds",
        "Allied forces (Israel, UK) may trigger some markets but not others—check which actors are specified",
        "Resolution sources vary (DoD announcements, credible media, etc.)—some are more gameable than others",
        "Low-probability Iran markets may underprice tail risk due to retail bias toward recent-news-driven pricing",
        "Oil price markets provide a natural hedge: if Iran troops materialize, crude spikes; if de-escalation, oil fades"
      ]
    }
  };
}

